public class PS1 {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static boolean ps(T r,int t){if(r==null)return false;t-=r.v;if(r.l==null&&r.r==null)return t==0;return ps(r.l,t)||ps(r.r,t);}
    public static void main(String[] a){T r=new T(5);r.l=new T(4);r.r=new T(8);r.l.l=new T(11);r.l.l.r=new T(2);System.out.println(ps(r,22));System.out.println(ps(r,27));System.out.println("O(n) — subtract at each node, check target==0 at leaf");}
}

import java.util.*;
public class PS2 {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static List<List<Integer>> res=new ArrayList<>();
    static void dfs(T n,int t,List<Integer> path){if(n==null)return;t-=n.v;path.add(n.v);if(n.l==null&&n.r==null&&t==0)res.add(new ArrayList<>(path));dfs(n.l,t,path);dfs(n.r,t,path);path.remove(path.size()-1);}
    static List<List<Integer>> pathSum(T r,int t){res=new ArrayList<>();dfs(r,t,new ArrayList<>());return res;}
    public static void main(String[] a){T r=new T(5);r.l=new T(4);r.r=new T(8);r.l.l=new T(11);r.l.l.l=new T(7);r.l.l.r=new T(2);r.r.l=new T(13);r.r.r=new T(4);r.r.r.r=new T(1);System.out.println(pathSum(r,22));System.out.println("Backtrack: add node, recurse, then path.remove(last).");}
}

public class MPS {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int max=Integer.MIN_VALUE;
    static int dfs(T r){if(r==null)return 0;int l=Math.max(dfs(r.l),0),ri=Math.max(dfs(r.r),0);max=Math.max(max,r.v+l+ri);return r.v+Math.max(l,ri);}
    static int maxPath(T r){max=Integer.MIN_VALUE;dfs(r);return max;}
    public static void main(String[] a){T r=new T(-10);r.l=new T(9);r.r=new T(20);r.r.l=new T(15);r.r.r=new T(7);System.out.println(maxPath(r));System.out.println("42 — max(0,child) ignores negatives. Update global=l+node+r.");}
}

public class SumLeaf {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int total=0;
    static void dfs(T r,int cur){if(r==null)return;cur=cur*10+r.v;if(r.l==null&&r.r==null){total+=cur;return;}dfs(r.l,cur);dfs(r.r,cur);}
    static int sumNumbers(T r){total=0;dfs(r,0);return total;}
    public static void main(String[] a){T r=new T(1);r.l=new T(2);r.r=new T(3);System.out.println(sumNumbers(r));T r2=new T(4);r2.l=new T(9);r2.r=new T(0);r2.l.l=new T(5);r2.l.r=new T(1);System.out.println(sumNumbers(r2));System.out.println("cur=cur*10+node.val at each level; add at leaf. O(n)");}
}

import java.util.*;
public class PS3 {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int count=0;
    static void dfs(T r,long cur,long t,Map<Long,Integer> pm){if(r==null)return;cur+=r.v;count+=pm.getOrDefault(cur-t,0);pm.merge(cur,1,Integer::sum);dfs(r.l,cur,t,pm);dfs(r.r,cur,t,pm);pm.merge(cur,-1,Integer::sum);}
    static int pathSumIII(T r,int t){count=0;Map<Long,Integer> pm=new HashMap<>();pm.put(0L,1);dfs(r,0,t,pm);return count;}
    public static void main(String[] a){T r=new T(10);r.l=new T(5);r.r=new T(-3);r.l.l=new T(3);r.l.r=new T(2);r.r.r=new T(11);r.l.l.l=new T(3);r.l.l.r=new T(-2);r.l.r.r=new T(1);System.out.println(pathSumIII(r,8));System.out.println("O(n) prefix sum + HashMap. pm.put(0,1) for paths from root. Backtrack: restore map after each subtree.");}
}

public class MPSNeg {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int maxPathSum(T r){int[]m={Integer.MIN_VALUE};mps(r,m);return m[0];}
    static int mps(T r,int[]m){if(r==null)return 0;int l=Math.max(mps(r.l,m),0),ri=Math.max(mps(r.r,m),0);m[0]=Math.max(m[0],r.v+l+ri);return r.v+Math.max(l,ri);}
    public static void main(String[] a){System.out.println(maxPathSum(new T(-3)));System.out.println("-3 — single node case; max must be updated even for negative-only trees");T r=new T(2);r.l=new T(-1);System.out.println(maxPathSum(r));System.out.println("2 — single node or single branch; max(0,child) handles one-way negativity");}
}

public class GoodNodes {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int good=0;
    static void dfs(T r,int maxSoFar){if(r==null)return;if(r.v>=maxSoFar){good++;maxSoFar=r.v;}dfs(r.l,maxSoFar);dfs(r.r,maxSoFar);}
    static int countGoodNodes(T r){good=0;dfs(r,Integer.MIN_VALUE);return good;}
    public static void main(String[] a){T r=new T(3);r.l=new T(1);r.r=new T(4);r.l.l=new T(3);r.r.l=new T(1);r.r.r=new T(5);System.out.println(countGoodNodes(r));System.out.println("4 — node is good if it's >= max value seen on path from root");System.out.println("O(n) DFS with running max");}
}

import java.util.*;
public class AllPaths2 {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static List<List<Integer>> all=new ArrayList<>();
    static void dfs(T r,int t,List<Integer> p){if(r==null)return;t-=r.v;p.add(r.v);if(r.l==null&&r.r==null&&t==0)all.add(new ArrayList<>(p));dfs(r.l,t,p);dfs(r.r,t,p);p.remove(p.size()-1);}
    static List<List<Integer>> paths(T r,int t){all=new ArrayList<>();dfs(r,t,new ArrayList<>());return all;}
    public static void main(String[] a){T r=new T(5);r.l=new T(4);r.r=new T(8);r.l.l=new T(11);r.l.l.l=new T(7);r.l.l.r=new T(2);r.r.l=new T(13);r.r.r=new T(4);r.r.r.r=new T(1);System.out.println(paths(r,22));System.out.println("Backtrack pattern: add→recurse→remove. O(n) time O(h) extra stack space");}
}

public class AnyPath {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int maxPathSum(T r){int[]m={Integer.MIN_VALUE};d(r,m);return m[0];}
    static int d(T r,int[]m){if(r==null)return 0;int l=Math.max(d(r.l,m),0),ri=Math.max(d(r.r,m),0);m[0]=Math.max(m[0],r.v+l+ri);return r.v+Math.max(l,ri);}
    static boolean hasAnyPathSum(T r,long t,Map<Long,Integer> pm,long cur){if(r==null)return false;cur+=r.v;if(pm.containsKey(cur-t))return true;pm.merge(cur,1,Integer::sum);boolean res=hasAnyPathSum(r.l,t,pm,cur)||hasAnyPathSum(r.r,t,pm,cur);pm.merge(cur,-1,Integer::sum);return res;}
    public static void main(String[] a){T r=new T(10);r.l=new T(5);r.r=new T(-3);r.l.l=new T(3);r.r.r=new T(11);java.util.HashMap<Long,Integer> pm=new java.util.HashMap<>();pm.put(0L,1);System.out.println(hasAnyPathSum(r,8,pm,0));System.out.println(maxPathSum(r));System.out.println("Prefix sum for any downward path. Max path for any direction.");}
}

public class PseudoPalin {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static int count=0;
    static void dfs(T r,int mask){if(r==null)return;mask^=(1<<r.v);if(r.l==null&&r.r==null){if((mask&(mask-1))==0)count++;}dfs(r.l,mask);dfs(r.r,mask);}
    static int pseudoPalindromicPaths(T r){count=0;dfs(r,0);return count;}
    public static void main(String[] a){T r=new T(2);r.l=new T(3);r.r=new T(1);r.l.l=new T(3);r.l.r=new T(1);r.r.r=new T(1);System.out.println(pseudoPalindromicPaths(r));System.out.println("2 — bitmask of digit frequencies. Palindrome: at most 1 bit set. (mask&(mask-1))==0 checks.");}
}

