public class T4Synth {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static boolean ps(T r,int t){if(r==null)return false;t-=r.v;if(r.l==null&&r.r==null)return t==0;return ps(r.l,t)||ps(r.r,t);}
    static int mps(T r){int[]m={Integer.MIN_VALUE};mpsH(r,m);return m[0];}
    static int mpsH(T r,int[]m){if(r==null)return 0;int l=Math.max(mpsH(r.l,m),0),ri=Math.max(mpsH(r.r,m),0);m[0]=Math.max(m[0],r.v+l+ri);return r.v+Math.max(l,ri);}
    static int ps3(T r,int t){int[]c={0};Map<Long,Integer> pm=new HashMap<>();pm.put(0L,1);ps3H(r,0,t,pm,c);return c[0];}
    static void ps3H(T r,long cur,int t,Map<Long,Integer> pm,int[]c){if(r==null)return;cur+=r.v;c[0]+=pm.getOrDefault(cur-t,0);pm.merge(cur,1,Integer::sum);ps3H(r.l,cur,t,pm,c);ps3H(r.r,cur,t,pm,c);pm.merge(cur,-1,Integer::sum);}
    public static void main(String[] a){T r=new T(5);r.l=new T(4);r.r=new T(8);r.l.l=new T(11);r.l.l.r=new T(2);System.out.println("pathSum22="+ps(r,22));T r2=new T(-10);r2.l=new T(9);r2.r=new T(20);r2.r.l=new T(15);r2.r.r=new T(7);System.out.println("maxPath="+mps(r2));T r3=new T(10);r3.l=new T(5);r3.r=new T(-3);r3.r.r=new T(11);r3.l.l=new T(3);r3.l.r=new T(2);Map<Long,Integer> pm=new HashMap<>();pm.put(0L,1);System.out.println("ps3(8)="+ps3(r3,8));boolean ok=ps(r,22)&&mps(r2)==42;System.out.println("All pass: "+ok);}
}

import java.util.*;
public class T4Final {
    static class T{int v;T l,r;T(int v){this.v=v;}}
    static boolean ps(T r,int t){if(r==null)return false;t-=r.v;if(r.l==null&&r.r==null)return t==0;return ps(r.l,t)||ps(r.r,t);}
    static int mps(T r){int[]m={Integer.MIN_VALUE};mH(r,m);return m[0];}
    static int mH(T r,int[]m){if(r==null)return 0;int l=Math.max(mH(r.l,m),0),ri=Math.max(mH(r.r,m),0);m[0]=Math.max(m[0],r.v+l+ri);return r.v+Math.max(l,ri);}
    static List<List<Integer>> allPaths(T r,int t){List<List<Integer>> res=new ArrayList<>();apH(r,t,new ArrayList<>(),res);return res;}
    static void apH(T r,int t,List<Integer> p,List<List<Integer>> res){if(r==null)return;t-=r.v;p.add(r.v);if(r.l==null&&r.r==null&&t==0)res.add(new ArrayList<>(p));apH(r.l,t,p,res);apH(r.r,t,p,res);p.remove(p.size()-1);}
    public static void main(String[] a){T r=new T(5);r.l=new T(4);r.r=new T(8);r.l.l=new T(11);r.l.l.l=new T(7);r.l.l.r=new T(2);r.r.l=new T(13);r.r.r=new T(4);r.r.r.r=new T(1);T r2=new T(-10);r2.l=new T(9);r2.r=new T(20);r2.r.l=new T(15);r2.r.r=new T(7);System.out.println("ps22="+ps(r,22));System.out.println("mps="+mps(r2));System.out.println("paths22="+allPaths(r,22));boolean ok=ps(r,22)&&mps(r2)==42&&allPaths(r,22).size()==2;System.out.println("All pass: "+ok);}
}
